import './Stack.scss';

import { Box } from ':components/Box';
import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React from 'react';
import type { StackProps } from './Stack.types';

export const Stack: FC<StackProps> = ({
	as,
	direction = 'vertical',
	spacing = 'none',
	align = 'stretch',
	justify = 'start',
	wrap = 'nowrap',
	className,
	dataTestId = 'Stack',
	...rest
}) => {
	const stackClassName = classNames(
		'dsb_stack',
		`dsb_stack__direction-${direction}`,
		`dsb_stack__spacing-${spacing}`,
		`dsb_stack__align-${align}`,
		`dsb_stack__justify-${justify}`,
		`dsb_stack__wrap-${wrap}`,
		className,
	);

	return <Box as={as} display="flex" className={stackClassName} dataTestId={dataTestId} {...rest} />;
};

Stack.displayName = 'Stack';
